111	    let count_w = rows.iter().map(|r| r.count.len()).max().unwrap_or(0); // OK: rows always contains n_bands=12 entries
112	    let mean_w = rows.iter().map(|r| r.mean.len()).max().unwrap_or(0); // OK: rows always contains n_bands=12 entries
