1	//! Apparatus-overhead calibration for [`TProbe`]. Measures the
2	//! hardware floor cost of two back-to-back `rdtsc` reads — the
3	//! bias contaminating every probe scope's stored `end_tsc -
4	//! start_tsc` delta — via a two-point fit matching the approach
5	//! in `iiac-perf/src/overhead.rs`.
6	//!
7	//! ### Why two-point, not single-point
8	//!
9	//! `rdtsc` isn't a serializing instruction. Two back-to-back
10	//! reads with nothing between can execute out-of-order and
11	//! measure a delta of 0–1 ticks — far below the true framing
12	//! cost. Bracketing with `_mm_lfence` overcorrects (lfence drains
13	//! the pipeline, which real work doesn't fully do), so single-
14	//! point measurement is biased in both directions.
15	//!
16	//! Two-point fits a line through empty benches at two `inner`
17	//! sizes (`N_LOW`, `N_HIGH`):
18	//! - raw delta at inner=N = framing + N · loop_per_iter
19	//! - slope between (N_LOW, raw_low) and (N_HIGH, raw_high) gives
20	//!   loop_per_iter; intercept gives framing.
21	//!
22	//! The `black_box(1)` inside the inner loop keeps OoO from
23	//! collapsing iterations and gives `loop_per_iter` a consistent
24	//! value. Noise amplification on framing:
25	//! `d(framing)/d(raw_low) = N_HIGH / (N_HIGH − N_LOW)`. At
26	//! 100/10_000 that's ~1.01 — any slop on `raw_low` propagates
27	//! roughly 1:1 to framing.
28	//!
29	//! We fit using raw tick deltas (not per-event values) in `f64`
30	//! arithmetic so integer truncation can't hide small framing
31	//! components.
32	//!
33	//! ### What gets subtracted
34	//!
35	//! Only framing. The two-point fit also yields
36	//! `loop_per_iter_ticks` (cost of one black_box iteration), which
37	//! we keep on the [`Overhead`] struct for diagnostics but do not
38	//! subtract from probe samples — the caller's inner-loop cost
39	//! (queue pop, deadline check, etc.) is part of what the user is
40	//! actually measuring, and the `black_box(1)` loop_per_iter
41	//! doesn't model it anyway.
42	//!
43	//! [`TProbe`]: crate::TProbe
44	//! [`TProbe::report`]: crate::TProbe::report
45	
46	use std::hint::black_box;
47	use std::time::{Duration, Instant};
48	
49	use crate::ticks;
50	
51	/// Calibration warmup iterations — lets CPU frequency boost ramp
52	/// before the first real sample.
53	pub const CAL_WARMUP: u64 = 10_000;
54	
55	/// Samples per minimum-pass. The reported floor approaches the
56	/// hardware lower bound as samples grow; 1,000 is enough for
57	/// convergence and keeps total calibration wall-clock short.
58	pub const CAL_SAMPLES: u64 = 1_000;
59	
60	/// Inner-loop count for the low-N calibration point.
61	pub const N_LOW: u64 = 100;
62	
63	/// Inner-loop count for the high-N calibration point. Wide spread
64	/// keeps noise amplification on fitted framing small
65	/// (`N_HIGH / (N_HIGH − N_LOW) ≈ 1.01`).
66	pub const N_HIGH: u64 = 10_000;
67	
68	/// Apparatus-overhead model fitted by [`calibrate`]. Callers pass
69	/// a reference to [`TProbe::report`] (as `Option<&Overhead>`) to
70	/// get framing subtracted from each stored per-event value.
71	///
72	/// [`TProbe::report`]: crate::TProbe::report
73	#[derive(Debug, Clone, Copy)]
74	pub struct Overhead {
75	    /// Fitted per-scope framing cost — the bias on every stored
76	    /// `end_tsc − start_tsc` delta regardless of scope batch size,
77	    /// in raw ticks. This is what gets subtracted via
78	    /// [`Self::per_event_ticks`].
79	    pub framing_ticks: u64,
80	    /// Fitted per-iteration cost of the `black_box(1)` empty
81	    /// bench loop body, in ticks. Kept for diagnostic visibility
82	    /// only — not used in the subtraction path (the real dispatch
83	    /// loop's per-iter cost is what we want to measure, not subtract).
84	    pub loop_per_iter_ticks: f64,
85	    /// Raw tick delta at `inner = N_LOW` (for `-v` style logging).
86	    pub cal_raw_low_ticks: u64,
87	    /// Raw tick delta at `inner = N_HIGH` (for `-v` style logging).
88	    pub cal_raw_high_ticks: u64,
89	    /// Wall-clock duration of the full calibration run.
90	    pub cal_duration: Duration,
91	}
92	
93	impl Overhead {
94	    /// Per-event framing correction at a given `batch`, in ticks:
95	    /// the framing is paid once per scope and amortized across
96	    /// `batch` events. Integer division truncates toward zero, so
97	    /// at `batch > framing_ticks` the correction rounds to zero.
98	    pub fn per_event_ticks(&self, batch: u64) -> u64 {
99	        self.framing_ticks / batch.max(1)
100	    }
101	}
102	
103	/// Measure the minimum raw tick delta over `samples` iterations
104	/// of an empty bench at inner size `inner`. Each iteration reads
105	/// `rdtsc`, runs `inner × black_box(1)` as filler (keeps OoO from
106	/// collapsing the scope to zero), reads `rdtsc` again.
107	#[inline(never)]
108	fn measure_empty_raw(samples: u64, inner: u64) -> u64 {
109	    let mut min_ticks = u64::MAX;
110	    for _ in 0..samples {
111	        let start = ticks::read_ticks();
112	        for _ in 0..inner {
113	            black_box(1u64);
114	        }
115	        let end = ticks::read_ticks();
116	        let delta = end.saturating_sub(start);
117	        if delta < min_ticks {
118	            min_ticks = delta;
119	        }
120	    }
121	    min_ticks
122	}
123	
124	/// Two-point calibration. Runs [`CAL_WARMUP`] warmup iterations,
125	/// then two minimum-passes at `inner = N_LOW` and `inner = N_HIGH`,
126	/// and fits
127	/// `raw_delta = framing + inner · loop_per_iter`. Blocks for
128	/// ~10 ms on a modern x86.
129	pub fn calibrate() -> Overhead {
130	    let cal_start = Instant::now();
131	
132	    for _ in 0..CAL_WARMUP {
133	        let a = ticks::read_ticks();
134	        black_box(a);
135	    }
136	
137	    let raw_low = measure_empty_raw(CAL_SAMPLES, N_LOW);
138	    let raw_high = measure_empty_raw(CAL_SAMPLES, N_HIGH);
139	
140	    let loop_per_iter_ticks = if raw_high > raw_low {
141	        (raw_high - raw_low) as f64 / (N_HIGH - N_LOW) as f64
142	    } else {
143	        0.0
144	    };
145	    let framing_f = (raw_low as f64 - N_LOW as f64 * loop_per_iter_ticks).max(0.0);
146	    let framing_ticks = framing_f.round() as u64;
147	
148	    Overhead {
